def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity == 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        elif ratio == 1:
            priorities[i] = 0
            continue
        score = 0
        for j in range(1, 21):
            factor = (-1)**(j+1)
            if j % 3 == 0:
                term = factor * (ratio ** (j/2)) / (j*1.5)
            else:
                term = factor * (ratio ** j) / j
            score += term
        adjustment = 1.0
        if capacity < item * 1.2:
            adjustment *= 3.0
        elif capacity < item * 1.7:
            adjustment *= 2.0
        elif capacity < item * 2.5:
            adjustment *= 1.3
        else:
            adjustment *= 1.1
        nearby_penalty = 0
        count = 0
        for k in range(max(0, i-2), min(n, i+3)):
            if k != i and bins[k] != 0:
                overlap_ratio = item / bins[k]
                if 0 < overlap_ratio < 1:
                    nearby_penalty += (1 - overlap_ratio)**3
                    count += 1
        if count > 0:
            nearby_penalty /= count
        isolation_bonus = 0
        if i == 0 or i == n-1:
            isolation_bonus = 0.05
        else:
            left = bins[i-1]
            right = bins[i+1]
            if left == 0 and right == 0:
                isolation_bonus = 0.1
        frag_penalty = 0
        for m in range(i+1, min(n, i+5)):
            if bins[m] < item * 0.5 and bins[m] != 0:
                frag_penalty += 0.2
        raw_score = -score * adjustment + nearby_penalty + frag_penalty - isolation_bonus
        if raw_score < 0:
            raw_score = 0
        priorities[i] = raw_score
    return priorities
